// ─── Layout & style constants ─────────────────────────────────────────────────

const NN = ['A','B','C','D'];
// Fixed 2×2 node positions in 100×100 viewBox
const NP = [[25,27],[75,27],[25,73],[75,73]];

// Color theme by min-toggle count
const DIFF = {
  2:{bg:'#f0faf2',bdr:'#2d7d46',badge:'#276639'},
  3:{bg:'#fefce8',bdr:'#b45309',badge:'#92400e'},
  4:{bg:'#fff7ed',bdr:'#c2410c',badge:'#9a3412'},
  5:{bg:'#fdf4ff',bdr:'#9333ea',badge:'#7e22ce'},
  6:{bg:'#eff6ff',bdr:'#2563eb',badge:'#1d4ed8'},
};

// Toggle state node styling: 0=forced-off, 1=forced-on, 2=free
const TSTYLE = {
  0:{fill:'#fee2e2',stroke:'#dc2626',text:'#7f1d1d'},
  1:{fill:'#dcfce7',stroke:'#16a34a',text:'#14532d'},
  2:{fill:'#f8fafc',stroke:'#94a3b8',text:'#64748b'},
};

// Observation node styling: 0=off, 1=on
const OSTYLE = {
  0:{fill:'#f8fafc',stroke:'#e2e8f0',text:'#cbd5e1'},
  1:{fill:'#1e293b',stroke:'#0f172a',text:'#f1f5f9'},
};

const DNSTYLE = {fill:'#ffffff',stroke:'#6b7280',text:'#374151'};

// ─── SVG primitives ──────────────────────────────────────────────────────────

function ArrowEdge({from, to, r=9, sw=1.5, color='#475569'}) {
  const [x1,y1]=NP[from],[x2,y2]=NP[to];
  const dx=x2-x1,dy=y2-y1,d=Math.sqrt(dx*dx+dy*dy);
  if(d<1) return null;
  const nx=dx/d,ny=dy/d,px=-ny,py=nx,hl=6,hw=3.2;
  const sx=x1+nx*r,sy=y1+ny*r;
  const tx=x2-nx*r,ty=y2-ny*r;
  const bx=tx-nx*hl,by=ty-ny*hl;
  return (
    <g>
      <line x1={sx} y1={sy} x2={bx} y2={by} stroke={color} strokeWidth={sw}/>
      <polygon points={`${tx},${ty} ${bx+px*hw},${by+py*hw} ${bx-px*hw},${by-py*hw}`} fill={color}/>
    </g>
  );
}

function DagSvg({edges, nodeStyle, size=100, r=9}) {
  const ns = nodeStyle || [DNSTYLE,DNSTYLE,DNSTYLE,DNSTYLE];
  return (
    <svg viewBox="0 0 100 100" width={size} height={size} style={{display:'block',flexShrink:0}}>
      {(edges||[]).map(([f,t],i)=>(
        <ArrowEdge key={i} from={f} to={t} r={r}/>
      ))}
      {[0,1,2,3].map(i=>{
        const [cx,cy]=NP[i],s=ns[i]||DNSTYLE;
        return (
          <g key={i}>
            <circle cx={cx} cy={cy} r={r} fill={s.fill} stroke={s.stroke} strokeWidth={1.5}/>
            <text x={cx} y={cy} textAnchor="middle" dominantBaseline="central"
              fontSize="9" fontWeight="700" fill={s.text} fontFamily="system-ui,sans-serif">
              {NN[i]}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

// ─── Toggle visualization ─────────────────────────────────────────────────────

function ToggleViz({td, edges, size=72, idx}) {
  const r = size <= 72 ? 8 : 10;
  return (
    <div style={{
      display:'flex',alignItems:'center',gap:10,padding:'10px 0',
      borderBottom:'1px solid #f1f5f9',
    }}>
      <div style={{
        fontSize:11,color:'#94a3b8',fontWeight:700,minWidth:18,
        fontVariantNumeric:'tabular-nums',flexShrink:0,
      }}>
        {idx+1}
      </div>

      {/* Intervention */}
      <DagSvg edges={edges} nodeStyle={td.toggle.map(v=>TSTYLE[v])} size={size} r={r}/>

      <div style={{color:'#cbd5e1',fontSize:18,flexShrink:0}}>→</div>

      {/* Observation */}
      <DagSvg edges={edges} nodeStyle={td.obs.map(v=>OSTYLE[v])} size={size} r={r}/>

      {/* Text labels */}
      <div style={{flex:1,fontSize:10,color:'#64748b',lineHeight:1.7,minWidth:0}}>
        <div style={{display:'flex',flexWrap:'wrap',gap:3,marginBottom:3}}>
          {td.toggle.map((v,i)=>(
            <span key={i} style={{
              padding:'1px 6px',borderRadius:3,fontSize:10,fontWeight:600,
              background:v===1?'#dcfce7':v===0?'#fee2e2':'#f1f5f9',
              color:v===1?'#166534':v===0?'#991b1b':'#64748b',
            }}>
              {NN[i]}={v===1?'on':v===0?'off':'—'}
            </span>
          ))}
        </div>
        <div style={{color:'#475569',fontFamily:'monospace',fontSize:10}}>
          {td.obs.map((v,i)=>(
            <span key={i} style={{
              marginRight:6,
              fontWeight:v?700:400,
              color:v?'#0f172a':'#94a3b8',
            }}>
              {NN[i]}={v?'on':'off'}
            </span>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── Grid thumbnail card ──────────────────────────────────────────────────────

function ClassCard({d, isSelected, onClick}) {
  const th = DIFF[d.n_min_toggles] || DIFF[6];
  const [hov, setHov] = useState(false);
  const active = isSelected || hov;
  return (
    <div
      onClick={onClick}
      onMouseEnter={()=>setHov(true)}
      onMouseLeave={()=>setHov(false)}
      style={{
        cursor:'pointer',borderRadius:8,padding:'10px 8px 8px',
        border:`2px solid ${active ? th.bdr : '#e2e8f0'}`,
        background:active ? th.bg : '#fafafa',
        display:'flex',flexDirection:'column',alignItems:'center',gap:4,
        transition:'border-color 0.12s, background 0.12s',
        boxShadow:isSelected?'0 2px 12px rgba(0,0,0,0.1)':'none',
      }}
    >
      <DagSvg edges={d.edges} size={80} r={8}/>
      <div style={{textAlign:'center',lineHeight:1.5}}>
        <div style={{fontWeight:600,fontSize:11,color:'#1e293b',
          whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',maxWidth:130}}>
          {d.edge_str}
        </div>
        <div style={{
          marginTop:5,display:'inline-block',
          background:th.badge,color:'#fff',
          borderRadius:4,padding:'2px 9px',fontSize:11,fontWeight:700,
        }}>
          {d.n_min_toggles} toggle{d.n_min_toggles!==1?'s':''}
        </div>
      </div>
    </div>
  );
}

// ─── Detail panel ─────────────────────────────────────────────────────────────

function DetailPanel({d}) {
  const th = DIFF[d.n_min_toggles] || DIFF[6];
  return (
    <div style={{
      marginTop:14,padding:'20px 24px',background:'#fff',
      border:`2px solid ${th.bdr}`,borderRadius:10,
      boxShadow:'0 4px 20px rgba(0,0,0,0.06)',
    }}>

      {/* Header */}
      <div style={{
        display:'flex',justifyContent:'space-between',
        alignItems:'flex-start',marginBottom:18,flexWrap:'wrap',gap:10,
      }}>
        <div>
          <div style={{fontSize:19,fontWeight:800,color:'#0f172a',letterSpacing:-0.3}}>
            {d.edge_str}
          </div>
          <div style={{fontSize:12,color:'#64748b',marginTop:5,lineHeight:1.6}}>
            {d.n_edges} directed edge{d.n_edges!==1?'s':''}{' · '}
            {d.n_members} labeled DAG{d.n_members!==1?'s':''} in iso-class{' · '}
            {d.n_hard} hard-to-distinguish (covered by exactly 1 toggle in min-set)
          </div>
        </div>
        <div style={{
          background:th.badge,color:'#fff',flexShrink:0,
          borderRadius:7,padding:'7px 16px',fontSize:15,fontWeight:800,
        }}>
          {d.n_min_toggles} toggle{d.n_min_toggles!==1?'s':''}
        </div>
      </div>

      {/* Body: canonical DAG + toggle details */}
      <div style={{display:'flex',gap:28,flexWrap:'wrap',alignItems:'flex-start'}}>

        {/* Canonical rep */}
        <div style={{flexShrink:0}}>
          <div style={sectionLabel}>Canonical Representative</div>
          <DagSvg edges={d.edges} size={140} r={13}/>
          <div style={{fontSize:10,color:'#94a3b8',marginTop:6,lineHeight:1.6,maxWidth:140}}>
            {d.edges.length===0
              ? <em>no edges</em>
              : d.edges.map(([u,v],i)=>(
                  <div key={i} style={{fontFamily:'monospace'}}>
                    {NN[u]}→{NN[v]}
                  </div>
                ))
            }
          </div>
        </div>

        {/* Toggle set */}
        <div style={{flex:1,minWidth:300}}>
          <div style={sectionLabel}>Minimal Toggle Set</div>

          {/* Legend */}
          <div style={{
            display:'flex',gap:14,marginBottom:10,fontSize:10,color:'#64748b',
            flexWrap:'wrap',
          }}>
            {[
              {label:'Forced on', bg:'#dcfce7', bdr:'#16a34a'},
              {label:'Forced off', bg:'#fee2e2', bdr:'#dc2626'},
              {label:'Free',       bg:'#f8fafc', bdr:'#94a3b8'},
            ].map(({label,bg,bdr})=>(
              <span key={label} style={{display:'flex',alignItems:'center',gap:4}}>
                <span style={{
                  display:'inline-block',width:12,height:12,borderRadius:3,
                  background:bg,border:`1.5px solid ${bdr}`,flexShrink:0,
                }}/>
                {label}
              </span>
            ))}
            <span style={{display:'flex',alignItems:'center',gap:4}}>
              <span style={{
                display:'inline-block',width:12,height:12,borderRadius:3,
                background:'#1e293b',border:'1.5px solid #0f172a',flexShrink:0,
              }}/>
              Observed on
            </span>
          </div>

          {d.min_toggles.map((td,i)=>(
            <ToggleViz key={i} td={td} edges={d.edges} size={68} idx={i}/>
          ))}
        </div>
      </div>

      {/* Hardest DAGs */}
      {d.hard_dags.length>0 && (
        <div style={{marginTop:20}}>
          <div style={sectionLabel}>
            Hardest-to-Distinguish ({d.n_hard} total, showing {d.hard_dags.length})
            <span style={{
              fontWeight:400,textTransform:'none',letterSpacing:0,
              fontSize:10,color:'#94a3b8',marginLeft:8,
            }}>
              — separated from canonical only by a single toggle in the min-set
            </span>
          </div>
          <div style={{display:'flex',flexWrap:'wrap',gap:8,marginTop:8}}>
            {d.hard_dags.map((edges,i)=>(
              <div key={i} style={{
                border:'1px solid #e2e8f0',borderRadius:6,padding:'6px 6px 3px',
                background:'#fafafa',display:'flex',flexDirection:'column',alignItems:'center',
              }}>
                <DagSvg edges={edges} size={58} r={7}/>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

const sectionLabel = {
  fontSize:11,fontWeight:700,color:'#94a3b8',
  textTransform:'uppercase',letterSpacing:0.8,marginBottom:8,
};

// ─── App ──────────────────────────────────────────────────────────────────────

export default function App() {
  const [sel, setSel] = useState(null);
  const detailRef = useRef(null);

  const sorted = [...DAG_DATA].sort((a,b)=>
    a.n_min_toggles-b.n_min_toggles || a.n_edges-b.n_edges
  );

  // Distribution summary
  const dist = {};
  sorted.forEach(d=>{ dist[d.n_min_toggles]=(dist[d.n_min_toggles]||0)+1; });

  // Scroll to detail when it opens
  useEffect(()=>{
    if(sel && detailRef.current) {
      detailRef.current.scrollIntoView({behavior:'smooth',block:'nearest'});
    }
  },[sel]);

  return (
    <div style={{
      fontFamily:"system-ui,-apple-system,'Segoe UI',sans-serif",
      maxWidth:960,margin:'0 auto',padding:24,color:'#0f172a',
    }}>

      {/* Title */}
      <div style={{marginBottom:22}}>
        <h1 style={{
          fontSize:23,fontWeight:800,margin:0,letterSpacing:-0.4,color:'#0f172a',
        }}>
          Minimal Toggle Sets for DAG Identification
        </h1>
        <p style={{fontSize:12,color:'#64748b',margin:'6px 0 0',lineHeight:1.7}}>
          4 labeled nodes {'{'}A,B,C,D{'}'} · 543 labeled DAGs · 31 non-isomorphic classes ·
          81 interventions (3⁴) · OR causal semantics · perfect observation ·
          minimum set found by exact brute-force set cover
        </p>

        {/* Summary badges */}
        <div style={{display:'flex',gap:8,marginTop:12,flexWrap:'wrap',alignItems:'center'}}>
          <span style={{fontSize:11,color:'#94a3b8',fontWeight:600}}>Min toggles needed:</span>
          {Object.entries(dist).sort((a,b)=>+a[0]-+b[0]).map(([k,v])=>{
            const th=DIFF[+k]||DIFF[6];
            return (
              <span key={k} style={{
                background:th.bg,border:`1.5px solid ${th.bdr}`,
                borderRadius:5,padding:'3px 10px',
                fontSize:11,fontWeight:700,color:th.badge,
              }}>
                {k}: {v} class{v!==1?'es':''}
              </span>
            );
          })}
        </div>
      </div>

      {/* Color legend */}
      <div style={{
        display:'flex',gap:12,marginBottom:18,flexWrap:'wrap',
        fontSize:11,color:'#64748b',padding:'8px 14px',
        background:'#f8fafc',borderRadius:7,border:'1px solid #e2e8f0',
        alignItems:'center',
      }}>
        <strong style={{color:'#475569',marginRight:4}}>Difficulty:</strong>
        {Object.entries(DIFF).map(([k,th])=>(
          <span key={k} style={{display:'flex',alignItems:'center',gap:5}}>
            <span style={{
              display:'inline-block',width:14,height:14,borderRadius:3,
              background:th.bg,border:`2px solid ${th.bdr}`,flexShrink:0,
            }}/>
            <span style={{color:th.badge,fontWeight:700}}>{k}</span>
            <span>toggle{+k!==1?'s':''}</span>
          </span>
        ))}
        <span style={{marginLeft:'auto',color:'#94a3b8',fontStyle:'italic',fontSize:10}}>
          Click any class to expand details
        </span>
      </div>

      {/* Overview grid */}
      <div style={{
        display:'grid',
        gridTemplateColumns:'repeat(auto-fill,minmax(138px,1fr))',
        gap:10,
      }}>
        {sorted.map(d=>(
          <ClassCard
            key={d.class_id}
            d={d}
            isSelected={sel?.class_id===d.class_id}
            onClick={()=>setSel(sel?.class_id===d.class_id ? null : d)}
          />
        ))}
      </div>

      {/* Detail panel */}
      <div ref={detailRef}>
        {sel && <DetailPanel d={sel}/>}
      </div>

      {/* Footer */}
      <div style={{
        marginTop:28,paddingTop:14,borderTop:'1px solid #e2e8f0',
        fontSize:11,color:'#94a3b8',lineHeight:1.9,
      }}>
        <strong style={{color:'#64748b'}}>Propagation:</strong>{' '}
        Intervention forces each node ON, OFF, or leaves it free.
        Forced nodes sever incoming edges (do-calculus).
        Free nodes activate if any parent is active (OR semantics).
        <br/>
        <strong style={{color:'#64748b'}}>Identification:</strong>{' '}
        Every pair of distinct labeled DAGs is separable by some single toggle
        (n_confusable = 0 universally). Minimum set size arises from the covering
        structure: no single toggle simultaneously separates all 542 others.
      </div>
    </div>
  );
}
